// Format Result - Kode dari materi NF Academy
// Parsing string JSON dan mengekstrak URL gambar dari resultUrls

const result = JSON.parse($json.data.resultJson);

return [{
  img1: result.resultUrls[0] || null,
  img2: result.resultUrls[1] || null,
  img3: result.resultUrls[2] || null,
  img4: result.resultUrls[3] || null
}];

// Loop Image - Kode dari materi NF Academy
// Menyiapkan data URL gambar untuk diproses satu per satu

const urls = [
  $json.img1,
  $json.img2,
  $json.img3,
  $json.img4
].filter(Boolean);

// jadikan 1 URL = 1 item
return urls.map((url, index) => ({
  json: {
    url,
    index: index + 1
  }
}));

